import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ArrowUpward, ArrowDownward } from '@mui/icons-material';
import response from './response.json';

interface CurrentRoute {
  routeName: string;
  estimatedTime: number;
  trafficLevel: string;
  distance: number;
}

interface AlternativeRoute {
  routeName: string;
  estimatedTime: number;
  trafficLevel: string;
  distance: number;
}

interface CommuteData {
  currentRoute: CurrentRoute;
  alternativeRoutes: AlternativeRoute[];
}

export default function Widget() {
  const commuteData = response.data as CommuteData;
  const { currentRoute, alternativeRoutes } = commuteData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              Current Route
            </Typography>
            <Typography variant="body1" fontWeight={500} sx={{ color: '#1F2937' }}>
              {currentRoute.routeName}
            </Typography>
            <Stack direction="row" spacing={1} alignItems="center" sx={{ mt: 0.5 }}>
              <Chip label={`${currentRoute.estimatedTime} mins`} color="primary" variant="outlined" />
              <Chip label={currentRoute.trafficLevel} sx={{ bgcolor: '#FFC107', color: '#FFFFFF' }} />
              <Chip label={`${currentRoute.distance} km`} variant="outlined" />
            </Stack>
          </Box>

          <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
            Alternative Routes
          </Typography>
          <Stack spacing={1}>
            {alternativeRoutes.map((route, index) => (
              <Box key={index}>
                <Typography variant="body2" fontWeight={500} sx={{ color: '#1F2937' }}>
                  {route.routeName}
                </Typography>
                <Stack direction="row" spacing={1} alignItems="center" sx={{ mt: 0.5 }}>
                  <Chip
                    label={`${route.estimatedTime} mins`}
                    icon={route.estimatedTime < currentRoute.estimatedTime ? <ArrowDownward /> : <ArrowUpward />}
                    color={route.estimatedTime < currentRoute.estimatedTime ? "success" : "error"}
                    variant="outlined"
                  />
                  <Chip label={route.trafficLevel} sx={{ bgcolor: route.trafficLevel === 'Light' ? '#4CAF50' : '#FFC107', color: '#FFFFFF' }} />
                  <Chip label={`${route.distance} km`} variant="outlined" />
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
